@rendermode InteractiveServer
@using sv_a11a6314a5604015bab4721752f4273a.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left sidebar: channel list ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h2>Channels</h2>
        </div>
        <ul class="channel-list">
            @if (channels is not null)
            {
                @foreach (var ch in channels)
                {
                    <li class="channel-item @(ch.Id == activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(ch)">
                        <div class="channel-name"># @ch.Name</div>
                        <div class="channel-desc">@Truncate(ch.Description, 40)</div>
                        @if (ch.UnreadCount > 0)
                        {
                            <span class="unread-badge">@ch.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="message-area @(threadOpen ? "thread-visible" : "")">
        @if (activeChannel is not null)
        {
            <div class="message-header">
                <h3># @activeChannel.Name</h3>
                <span class="header-desc">@activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="messageListRef" @onscroll="OnMessageScroll">
                @if (loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (messages is not null)
                {
                    @foreach (var msg in messages)
                    {
                        <div class="message-row" @onmouseover="() => hoveredMessageId = msg.Id"
                             @onmouseout="() => { if (hoveredMessageId == msg.Id) hoveredMessageId = null; }">
                            <div class="message-bubble">
                                <div class="message-meta">
                                    <span class="author">@msg.Author</span>
                                    <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                                </div>
                                <div class="message-content">@msg.Content</div>

                                @if (msg.Reactions.Count > 0)
                                {
                                    <div class="reaction-row">
                                        @foreach (var r in msg.Reactions)
                                        {
                                            <span class="reaction-badge" title="@string.Join(", ", r.Users)">
                                                @r.Emoji @r.Users.Count
                                            </span>
                                        }
                                    </div>
                                }

                                @{ var summary = threadSummaries.GetValueOrDefault(msg.Id); }
                                @if (summary is not null)
                                {
                                    <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                        @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                        &middot; Last @FormatRelativeTime(summary.LastReplyAt)
                                    </button>
                                }
                            </div>

                            @if (hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg)">💬 Reply</button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" title="Add reaction"
                                                @onclick="() => ToggleEmojiPicker(msg.Id)">😀 React</button>
                                        @if (emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in commonEmojis)
                                                {
                                                    <button class="emoji-option"
                                                            @onclick="() => AddReactionAsync(msg.Id, emoji)">@emoji</button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="newMessageText" @bind:event="oninput"
                          placeholder="Type a message…"
                          @onkeydown="OnMessageKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (threadOpen && threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <div class="message-meta">
                    <span class="author">@threadRootMessage.Author</span>
                    <span class="timestamp">@FormatRelativeTime(threadRootMessage.SentAt)</span>
                </div>
                <div class="message-content">@threadRootMessage.Content</div>
            </div>

            <div class="thread-replies">
                @if (threadMessages is not null)
                {
                    @foreach (var reply in threadMessages)
                    {
                        <div class="message-bubble thread-reply">
                            <div class="message-meta">
                                <span class="author">@reply.Author</span>
                                <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>
                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <span class="reaction-badge">@r.Emoji @r.Users.Count</span>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="threadReplyText" @bind:event="oninput"
                          placeholder="Reply…"
                          @onkeydown="OnThreadKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "🙏"];

    // Data
    private List<Channel>? channels;
    private int activeChannelId;
    private Channel? activeChannel;
    private List<Message>? messages;
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private int messageSkip;
    private bool loadingOlder;
    private bool allOlderLoaded;

    // Thread state
    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message>? threadMessages;
    private string threadReplyText = string.Empty;

    // UI state
    private string newMessageText = string.Empty;
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;
    private ElementReference messageListRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannelId = channel.Id;
        activeChannel = channel;
        messageSkip = 0;
        allOlderLoaded = false;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messageSkip = messages.Count;
        BuildThreadSummaries();
        CloseThread();
        await ChatService.MarkChannelReadAsync(channel.Id);
        await RefreshChannelUnread(channel.Id);
    }

    private async Task RefreshChannelUnread(int channelId)
    {
        var refreshed = await ChatService.GetChannelsAsync();
        if (refreshed is not null)
        {
            channels = refreshed;
        }
    }

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        if (messages is null) return;

        var rootIds = messages.Where(m => m.ReplyToId is null).Select(m => m.Id).ToHashSet();
        var replies = messages.Where(m => m.ReplyToId is not null && rootIds.Contains(m.ReplyToId.Value));

        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }
    }

    // Scroll-to-top pagination
    private async Task OnMessageScroll()
    {
        if (loadingOlder || allOlderLoaded || activeChannel is null) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 1)
        {
            await LoadOlderMessagesAsync();
        }
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (activeChannel is null) return;
        loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messageSkip, PageSize);
        if (older.Count == 0)
        {
            allOlderLoaded = true;
        }
        else
        {
            messages = [..older, ..(messages ?? [])];
            messageSkip += older.Count;
            BuildThreadSummaries();
        }

        loadingOlder = false;
    }

    // Sending messages
    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannel is null) return;
        var sent = await ChatService.SendMessageAsync(activeChannel.Id, newMessageText.Trim(), null);
        messages ??= [];
        messages.Add(sent);
        messageSkip++;
        newMessageText = string.Empty;
        await ScrollToBottom();
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // Thread operations
    private async Task OpenThreadAsync(Message rootMsg)
    {
        threadRootMessage = rootMsg;
        threadMessages = await ChatService.GetThreadAsync(rootMsg.Id);
        threadOpen = true;
        emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadMessages = null;
        threadReplyText = string.Empty;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannel is null) return;
        var reply = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyText.Trim(), threadRootMessage.Id);
        threadMessages ??= [];
        threadMessages.Add(reply);
        threadReplyText = string.Empty;

        // Update summary in main list
        var existing = threadSummaries.GetValueOrDefault(threadRootMessage.Id);
        threadSummaries[threadRootMessage.Id] = new ThreadSummary(
            threadRootMessage.Id,
            (existing?.ReplyCount ?? 0) + 1,
            reply.SentAt);
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // Reactions
    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Refresh messages to reflect the new reaction
        if (activeChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannel.Id, 0, messageSkip);
            BuildThreadSummaries();
        }
    }

    // Helpers
    private async Task ScrollToBottom()
    {
        await JS.InvokeVoidAsync("eval", "setTimeout(() => { let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight; }, 50)");
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }

    private static string Truncate(string text, int maxLen) =>
        text.Length <= maxLen ? text : text[..(maxLen - 1)] + "…";
}
"}

